INSERT INTO "Course" (title, slug, description, category, price, image, "updatedAt") VALUES
('Toán Tiểu Học - Lớp 1 Cơ Bản', 'toan-tieu-hoc-lop-1', 'Giúp bé làm quen với các con số, hình học cơ bản và phát triển tư duy logic sớm.', 'Toán tiểu học', '1000000', '/images/offline_math_class.jpg', NOW()),
('Toán Tiểu Học - Lớp 5 Nâng Cao', 'toan-tieu-hoc-lop-5', 'Ôn tập và nâng cao kiến thức toán lớp 5, chuẩn bị hành trang vào lớp 6 trường điểm.', 'Toán tiểu học', '1200000', '/images/online_math_class.jpg', NOW()),
('Toán THCS - Lớp 6 Tổng Ôn', 'toan-thcs-lop-6', 'Hệ thống hóa kiến thức đầu cấp, giúp học sinh nắm vững phương pháp giải các dạng bài tập mới.', 'Toán THCS', '1500000', 'https://toan.vn/wp-content/uploads/2025/06/z6654844451158_4c348eebf8267220e5db3fe8fec2afb2.jpg', NOW()),
('Toán THCS - Lớp 9 Ôn thi vào 10', 'toan-thcs-lop-9', 'Lộ trình ôn tập chuyên sâu, bám sát cấu trúc đề thi vào lớp 10 của các trường THPT.', 'Toán THCS', '2000000', '/images/offline_math_class.jpg', NOW()),
('Toán PTTH - Lớp 10 Định Hướng', 'toan-ptth-lop-10', 'Làm quen với đại số và hình học không gian, xây dựng nền tảng vững chắc cho 3 năm cấp 3.', 'Toán PTTH', '2200000', 'https://toan.vn/wp-content/uploads/2025/01/nhung-kien-thuc-dai-so-lop-7-hoc-sinh-can-nam-vung-scaled.jpg', NOW()),
('Toán PTTH - Lớp 11 Chuyên Đề', 'toan-ptth-lop-11', 'Tập trung vào các chuyên đề khó như Lượng Giác, Tổ Hợp Xác Suất, Hình Không Gian.', 'Toán PTTH', '2500000', '/images/online_math_class.jpg', NOW()),
('Luyện thi Đại học - Toán 12 Cơ Bản', 'luyen-thi-dai-hoc-toan-12-co-ban', 'Ôn luyện bám sát cấu trúc đề thi tốt nghiệp THPT, đảm bảo mục tiêu 7-8 điểm.', 'Luyện thi đại học', '3000000', '/images/offline_math_class.jpg', NOW()),
('Luyện thi Đại học - Toán 12 Nâng Cao 9+', 'luyen-thi-dai-hoc-toan-12-nang-cao', 'Khóa học trọng điểm giúp học sinh hệ thống toàn bộ kiến thức, rèn kỹ năng giải đề khó để đạt 9+.', 'Luyện thi đại học', '4000000', 'https://toan.vn/wp-content/uploads/2025/06/z6654844451158_4c348eebf8267220e5db3fe8fec2afb2.jpg', NOW());
INSERT INTO "Teacher" (name, avatar, bio, role, exp, students, "updatedAt") VALUES
('Thầy Dũng Toán', 'https://toan.vn/wp-content/uploads/2026/07/Dang-Huy-Hoang-Toanvn.jpg', 'Khóa học Toán chuyên sâu dành cho học sinh muốn chinh phục điểm 9+ và thi học sinh giỏi.', 'Chuyên gia Luyện thi 9+', '15 năm', '5000+', NOW()),
('Thầy Trần Hồng Hà & Thầy Nguyễn Văn Dũng', '', 'Khóa học môn Toán (Chinh phục điểm 8.5+ đến 10).', 'Tổ trưởng chuyên môn', '12 năm', '3000+', NOW()),
('Thầy Thanh & Cô Linh', '', 'Khóa học Toán tư duy & Luyện thi chuyển cấp (Lớp 5 lên 6).', 'Giáo viên Khối Tiểu Học', '8 năm', '2000+', NOW()),
('Thầy Tùng & Thầy Dũng', 'https://toan.vn/wp-content/uploads/2026/07/Truong-quoc-dat-toanvn.jpg', 'Chuyên gia luyện thi Toán THPT, bám sát đề thi đại học với phương pháp giải trắc nghiệm siêu tốc.', 'Giáo viên Toán THPT', '10 năm', '4500+', NOW()),
('Cô Lan Anh & Cô Minh Châu', '', 'Đồng hành cùng học sinh mất gốc, củng cố nền tảng kiến thức, lấy lại tự tin với môn Toán THCS.', 'Giáo viên Khối THCS', '7 năm', '1500+', NOW());
